queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?science_lab a :Science_Lab .
    ?science_lab p:name ?name .
    ?science_lab p:Available_Resources ?available_resources_f .
    FILTER(STR(?available_resources_f) = "Computers")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?art_studio a :Art_Studio .
    ?art_studio p:name ?name .
    ?art_studio p:Available_Resources ?available_resources_f .
    FILTER(STR(?available_resources_f) = "Computers")
    BIND(?name AS ?o0)
  }
}

